import math

fn statistics_ops(v: List[Float64]) -> Tuple[Float64, Float64, Float64]:
    var n = len(v)
    var mean: Float64 = 0
    for x in v: mean += x[]
    mean /= n
    var sv = sort(v)
    var median: Float64
    if n % 2 == 1:
        median = sv[n // 2]
    else:
        median = (sv[n // 2 - 1] + sv[n // 2]) / 2.0
    var variance: Float64 = 0
    for x in v: variance += (x[] - mean) ** 2
    variance /= n
    return (mean, median, math.sqrt(variance))
